html {

    /* === Generic === */

    --text-color: #333;

    --header-height: 50px;

    --primary-color: #0fb1ca;
    --primary-font-color: #ffffff;
    --primary-color-offline: #9b9b9b;

    --secondary-color: #3fc0d4;
    --secondary-font-color: #ffffff;
    --secondary-color-offline: #b7b7b7;


    /* === Buttons === */

    --button-primary-bg: #231f20;
    --button-primary-border: 1px solid #231f20;
    --button-primary-text: #ffffff;
    --button-primary-ripple: #ffffff;

    --button-secondary-bg: transparent;
    --button-secondary-border: 1px solid #231f20;
    --button-secondary-text: #231f20;
    --button-secondary-ripple: #000000;

    --button-disabled-bg: #9b9b9b;
    --button-disabled-border: 1px solid #9b9b9b;
    --button-disabled-text: #ffffff;
    --button-disabled-ripple: #ffffff;

    --button-selected-bg: #0fb1ca;
    --button-selected-border: 1px solid #0fb1ca;
    --button-selected-text: #ffffff;
    --button-selected-ripple: #ffffff;


    /* === Incident lists === */

    --incident-list-incident-bg: #ffffff;
    --incident-list-incident-text: #000000;
    --incident-list-incident-border-color: #f2f2f2;
    --incident-list-incident-respondents-bg: #ffffff;
    --incident-list-incident-role-bg: transparent;
    --incident-list-incident-role-border: 1px solid #f0f0f0;
    --incident-list-incident-support-role-bg: #f6f6f6;
    --incident-list-incident-support-role-border: 1px solid #ffffff;

    --incident-list-closed-incident-bg: #f2f2f2;
    --incident-list-closed-incident-text: #000000;
    --incident-list-closed-incident-border-color: #ffffff;
    --incident-list-closed-incident-respondents-bg: #ffffff;
    --incident-list-closed-incident-role-bg: transparent;
    --incident-list-closed-incident-role-border: 1px solid #f0f0f0;
    --incident-list-closed-incident-support-role-bg: #f6f6f6;
