    --incident-header-severity-width: 170px;
    --incident-header-location-width: 340px;
    --incident-header-priority-width: 125px;
    --incident-header-patient-type-width: 130px;
    --incident-header-creator-width: 175px;
    --incident-header-severity-change-width: 200px;


    /* === Various response statuses === */

    --response-status-empty-bg: #ffffff;
    --response-status-empty-border: 1px solid #ededed;
    --response-status-empty-text: #444444;

    --response-status-received-bg: #f2f2f2;
    --response-status-received-border: 1px solid #ededed;
    --response-status-received-text: #444444;

