    --response-status-arrived-text: #ffffff;

    --response-status-stand-in-bg: #0fb1ca;
    --response-status-stand-in-border: 1px solid #0fb1ca;
    --response-status-stand-in-text: #ffffff;

    --response-status-off-duty-bg: #9b9b9b;
